    20→      --brand-secondary: #F78E21;
    21→
    22→      /* Neutral Scale - Exactes de l'inspiration */
    23→      --neutral-darkest: #000000;
    24→      --neutral-dark-900: #22242B;
    25→      --neutral-dark-800: #2F323A;
    26→      --neutral-dark-700: #5D5C5B;
    27→      --neutral-light-300: #D2D3D4;
    28→      --neutral-lightest: #FFFFFF;
    29→
    30→      /* Backgrounds */
