    43→      --text-secondary: #A1A1AA;
    44→      --text-muted: #71717A;
    45→
    46→      /* Spacing */
    47→      --space-1: 0.25rem;
    48→      --space-2: 0.5rem;
    49→      --space-3: 0.75rem;
    50→      --space-4: 1rem;
    51→      --space-6: 1.5rem;
    52→      --space-8: 2rem;
    53→      --space-12: 3rem;
    54→      --space-16: 4rem;
    55→      --space-20: 5rem;
    56→
    57→      /* Radius */
    58→      --radius-sm: 0.375rem;
    59→      --radius-md: 0.5rem;
    60→      --radius-lg: 0.75rem;
    61→      --radius-xl: 1rem;
    62→      --radius-2xl: 1.5rem;
    63→      --radius-full: 9999px;
    64→
    65→      /* Shadows */
    66→      --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
    67→      --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.3);
    68→      --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.4);
    69→      --shadow-glow: 0 0 30px rgba(247, 81, 5, 0.3);
    70→    }
    71→
    72→    body {
    73→      font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
    74→      background: var(--bg-primary);
