    90→      position: fixed;
    91→      top: 0;
    92→      left: 0;
    93→      right: 0;
    94→      z-index: 1000;
    95→      background: rgba(0, 0, 0, 0.9);
    96→      backdrop-filter: blur(12px);
    97→      border-bottom: 1px solid var(--border-subtle);
    98→    }
    99→
   100→    .nav-container {
